broadcast use vstd::std_specs::vec::group_vec_axioms;
    let premise = ({
        &&& (match ov {
            Some(e1) => r1.is_some() && e1@ == r1.get_Some_0()@,
            None => r1.is_None(),
        })
        &&& (match ov {
            Some(e1) => r2.is_some() && e1@ == r2.get_Some_0()@,
            None => r2.is_None(),
        })
    });
    if premise {
        match ov {
            Some(e1) => {
                assert(r1 is Some);
                assert(r2 is Some);
                assert(e1@ == r1->Some_0@);
                assert(e1@ == r2->Some_0@);
                assert(r1->Some_0@ == r2->Some_0@);
                assert(r1->Some_0 =~= r2->Some_0);
                assert(r1->Some_0 == r2->Some_0);
            }
            None => {
                assert(r1 is None);
                assert(r2 is None);
            }
        }
        assert(det_clone_option_vec_u8_equal(r1, r2));
    }
